use super::*;
use common::components::{TiptapEditor, Typo, Variant, Weight};

#[component]
pub fn ViewerPage(space_id: SpacePartition) -> Element {
    let mut content = use_signal(|| {
        r#"<section><h1>연구 개요</h1><ol><li><strong>연구 배경 및 필요성</strong><ul><li><strong>현안의 대두 및 입법 동향</strong><ul><li>최근 몇 년 동안 여러 국가에서 해당 현안에 대한 입법 움직임이 활발하게 진행되고 있다.</li><li>입법 과정에서 다양한 이해관계자의 의견이 수렴되어야 하는 복잡한 상황이 조성되고 있다.</li><li>해당 현안에 대한 국제적 관심이 증가함에 따라 국내 입법에도 영향을 미칠 가능성이 높다.</li></ul></li><li><strong>쟁점의 복합성과 갈등 구조</strong><ul><li>이 현안은 다양한 사회적, 경제적, 윤리적 쟁점을 포함하고 있어 복합적인 문제로 대두되고 있다.</li><li>이해관계자 간의 갈등이 심화됨에 따라 해결책 도출에 어려움이 있다.</li><li>갈등 구조를 이해하고 해결 방안을 모색하는 것이 중요하다.</li></ul></li><li><strong>정책 결정의 딜레마와 숙고된 여론의 필요성</strong><ul><li>정책 결정자들은 다양한 이해관계와 복잡한 쟁점으로 인해 딜레마에 직면해 있다.</li><li>숙고된 여론을 반영한 정책 결정이 필요하다.</li><li><table border=\"1\"><tr><th>이해관계자</th><th>입장</th></tr><tr><td>정부</td><td>규제 강화</td></tr><tr><td>산업체</td><td>자율 규제 강화</td></tr><tr><td>시민단체</td><td>엄격한 규제 요구</td></tr></table></li></ul></li></ul></li><li><strong>의제의 특성</strong><ul><li>해당 현안은 다각적인 접근이 필요한 복합적인 의제이다.</li><li>장기적인 시각에서 지속 가능한 해결책을 모색해야 한다.</li><li>다양한 분야와 학문적 접근이 필요한 복합적인 특성을 지니고 있다.</li></ul></li><li><strong>조사 목적</strong><ul><li><strong>핵심 목적</strong><ul><li>현안에 대한 깊이 있는 이해를 바탕으로 정책 제언을 도출하는 것이 핵심 목적이다.</li><li>다양한 이해관계자의 입장을 파악하고 종합적인 분석을 통해 해결책을 제시한다.</li><li>장기적인 시각에서 지속 가능한 정책 방향을 제시하는 것을 목표로 한다.</li></ul></li><li><strong>방법론적 혁신</strong><ul><li>기존의 연구 방법론을 확장하여 다양한 데이터 소스를 활용한다.</li><li>양적 분석과 질적 분석을 결합하여 종합적인 연구를 진행한다.</li><li>다양한 이해관계자와의 협력을 통해 연구의 타당성을 높인다.</li></ul></li><li><strong>기대 성과</strong><ul><li>현안에 대한 종합적인 이해를 제공하여 정책 결정에 도움을 줄 것으로 기대된다.</li><li>다양한 이해관계자의 입장을 반영한 정책 제언을 통해 갈등을 완화할 수 있을 것으로 기대된다.</li><li>장기적인 시각에서 지속 가능한 정책 방향을 제시함으로써 사회적 합의를 도출할 수 있을 것으로 기대된다.</li></ul></li></ul></li></ol></section><section><h1>조사 설계 및 데이터 수집</h1><ol><li><strong>조사 설계</strong><ul><li><strong>목적 설정</strong><ul><li>조사의 목적과 범위를 명확히 설정하여 조사 설계의 기본 방향을 결정하였다.</li><li>목적 설정을 통해 필요한 데이터의 종류와 수집 방법을 결정하였다.</li><li>목적 설정은 조사의 효율성과 타당성을 높이는 데 기여하였다.</li></ul></li><li><strong>대상 선정</strong><ul><li>조사 대상을 선정함에 있어 대표성과 다양성을 고려하였다.</li><li>대상 선정 과정에서 윤리적 고려사항을 반영하여 공정성을 확보하였다.</li><li>선정된 대상은 조사의 신뢰성과 타당성을 높이는 데 기여하였다.</li></ul></li></ul></li><li><strong>여론조사 진행 절차</strong><ul><li><strong>온라인 의견 조사</strong><ul><li>온라인 의견 조사를 통해 참여자들의 초기 의견을 수렴하였다.</li><li>온라인 의견 조사는 폭넓은 참여를 유도하고 다양한 의견을 반영하는 데 도움이 되었다.</li><li>수집된 의견은 후속 조사 단계의 기반이 되었다.</li></ul></li><li><strong>정보 제공</strong><ul><li>참여자들에게 필요한 정보를 제공함으로써 의사결정의 질을 높였다.</li><li>제공된 정보는 객관적이고 신뢰할 수 있는 출처에서 확보하였다.</li><li>참여자들이 충분한 정보를 바탕으로 의견을 표명할 수 있도록 하였다.</li></ul></li><li><strong>비실시간 온라인 토의</strong><ul><li>비실시간 온라인 토의를 통해 참여자들 간의 상호작용을 촉진하였다.</li><li>토의 과정에서 발생한 의견과 반응을 체계적으로 기록하였다.</li><li>토의 결과는 후속 조사 단계에 반영되었다.</li></ul></li><li><strong>사후 온라인 의견 조사</strong><ul><li>사후 온라인 의견 조사를 통해 토의 결과에 대한 피드백을 수집하였다.</li><li>수집된 피드백은 조사의 타당성과 신뢰성을 향상시키는 데 기여하였다.</li><li>사후 의견 조사 결과는 최종 분석에 반영되었다.</li></ul></li><li><strong>데이터 종합 분석</strong><ul><li>수집된 데이터를 종합적으로 분석하여 결과를 도출하였다.</li><li>분석 과정에서 다양한 통계적 기법을 활용하였다.</li><li>종합 분석 결과는 조사의 목적을 달성하는 데 기여하였다.</li></ul></li></ul></li><li><strong>블록체인 기술 적용 방안</strong><ul><li><strong>DID</strong><ul><li>분산 식별자(DID)를 활용하여 참여자의 신원을 안전하게 관리하였다.</li><li>DID를 통해 참여자의 프라이버시를 보호하고 데이터 무결성을 확보하였다.</li><li>DID 기술은 조사 과정의 투명성과 신뢰성을 높이는 데 기여하였다.</li></ul></li><li><strong>무결성 보장</strong><ul><li>블록체인 기술을 활용하여 데이터의 무결성을 보장하였다.</li><li>데이터 변조 방지를 통해 조사 결과의 신뢰성을 향상시켰다.</li><li>무결성 보장은 조사 과정의 공정성과 타당성을 높이는 데 기여하였다.</li></ul></li><li><strong>투명성 및 감사 가능성</strong><ul><li>블록체인의 투명성을 활용하여 조사 과정을 공개하였다.</li><li>감사 가능성을 통해 조사 결과에 대한 신뢰도를 높였다.</li><li>투명성과 감사 가능성은 조사의 공정성과 신뢰성을 강화하는 데 기여하였다.</li></ul></li><li><strong>인센티브 지급 자동화/Smart Contract</strong><ul><li>스마트 컨트랙트를 활용하여 인센티브 지급을 자동화하였다.</li><li>자동화된 인센티브 지급은 조사 참여자의 동기 부여에 기여하였다.</li><li>스마트 컨트랙트는 조사 과정의 효율성과 신뢰성을 높이는 데 기여하였다.</li></ul></li></ul></li><li><strong>분석 방법</strong><ul><li><strong>정량 분석<section><h1>분석 결과</h1><ol><li><strong>공론형 여론조사: 의견 변화 분석</strong><ul><li><strong>전체 의견 변화 추이</strong><ul><li>참가자들의 의견은 공론형 여론조사 기간 동안 상당한 변화를 보였으며, 이는 논의의 심도와 다양한 관점의 충돌을 반영한다.</li><li>초기 여론조사와 최종 여론조사 간의 의견 변화 비율은 전반적으로 증가 추세를 보여 주제에 대한 이해와 관심이 심화되었음을 시사한다.</li><li>해당 데이터 없음으로 구체적인 의견 변화 비율을 제시할 수 없다.</li></ul></li></ul></li><li><strong>사전 설문 문항 분석</strong><ul><li>사전 설문에서 얻은 데이터는 참가자들의 초기 인식과 태도를 파악하는 데 중요한 역할을 했다.</li><li>설문 결과는 주제에 대한 참가자들의 기존 지식과 관심사를 반영하며, 이를 통해 공론형 여론조사의 방향성을 설정하는 데 도움이 되었다.</li><li>해당 데이터 없음으로 사전 설문의 구체적인 결과를 제시할 수 없다.</li></ul></li><li><strong>토론 내용 분석</strong><ul><li><strong>토론 분석_LDA</strong><ul><li>LDA 분석을 통해 토론에서 주요 주제와 키워드를 추출하였으며, 이는 토론의 중심 내용을 이해하는 데 도움이 되었다.</li><li>토론 내용의 주제 분포는 다양한 관점과 의견이 존재함을 보여주었다.</li><li>해당 데이터 없음으로 구체적인 주제 분포를 제시할 수 없다.</li></ul></li><li><strong>토론 분석_TF-IDF</strong><ul><li>TF-IDF 분석을 통해 토론에서 중요한 단어와 문구를 식별하였으며, 이는 토론의 핵심 메시지를 파악하는 데 도움이 되었다.</li><li>빈도가 높은 단어와 문구는 주제에 대한 참가자들의 공통된 관심사를 반영한다.</li><li>해당 데이터 없음으로 구체적인 단어와 문구를 제시할 수 없다.</li></ul></li><li><strong>토론 분석_Text Network</strong><ul><li>텍스트 네트워크 분석을 통해 토론에서 단어 간의 연결 관계를 분석하였으며, 이는 토론의 구조와 흐름을 이해하는 데 도움이 되었다.</li><li>네트워크 분석 결과는 토론에서 중요한 개념과 아이디어의 연결성을 보여준다.</li><li>해당 데이터 없음으로 구체적인 연결 관계를 제시할 수 없다.</li></ul></li><li><strong>통합 분석</strong><ul><li>다양한 분석 방법을 통합하여 토론의 전체적인 흐름과 주요 내용을 파악하였다.</li><li>통합 분석 결과는 토론의 복잡성과 다양성을 반영하며, 주제에 대한 심층 이해를 제공한다.</li><li>해당 데이터 없음으로 구체적인 통합 분석 결과를 제시할 수 없다.</li></ul></li></ul></li></ol></section><section><h1>결론 및 제언</h1><ol><li><strong>연구 결과 요약</strong><ul><li><strong>주요 발견</strong><ul><li>블록체인 기반 공론조사는 기존 방법론에 비해 응답자의 익명성과 데이터 무결성을 효과적으로 보장하였다.</li><li>참여자의 의견 변화 추적이 가능하여 의견 형성 과정을 더 명확하게 이해할 수 있었다.</li><li>참여자의 참여도가 높아 보다 다양한 의견을 수집할 수 있었다.</li></ul></li></ul></li><li><strong>의견 변화의 패턴과 원인</strong><ul><li><strong>의견 변화 패턴</strong><ul><li>참여자들의 의견 변화는 주로 새로운 정보 제공과 토론을 통해 이루어졌다.</li><li>익명성이 보장되어 참여자들은 더 자유롭게 의견을 표현하고 변경할 수 있었다.</li><li>블록체인의 투명성 덕분에 참여자들은 다른 참여자의 의견 변화를 추적하여 더 깊은 고찰을 할 수 있었다.</li></ul></li><li><strong>의견 변화의 원인</strong><ul><li>새로운 정보와 데이터의 제공이 의견 변화의 주요 원인으로 나타났다.</li><li>다른 참여자와의 상호작용과 토론이 의견 변화에 큰 영향을 미쳤다.</li><li>익명성과 투명성이 보장되어 참여자들은 더 진지하고 성찰적인 태도로 의견을 형성하였다.</li></ul></li></ul></li><li><strong>블록체인 기반 공론조사 방법론의 가능성</strong><ul><li><strong>장점</strong><ul><li>익명성과 데이터 무결성 보장으로 인한 참여자 신뢰도 향상.</li><li>의견 변화 추적 기능을 통한 의견 형성 과정의 명확한 이해.</li><li>투명성과 공정성 보장으로 인한 결과의 신뢰성 증가.</li></ul></li><li><strong>한계</strong><ul><li>기술적 복잡성으로 인한 참여자 접근성 제한.</li><li>블록체인 기술의 고비용 문제.</li><li>일반 대중의 블록체인 이해도 부족으로 인한 참여 규모 제한.</li></ul></li><li><strong>개선 제언</strong><ul><li>블록체인 기술에 대한 대중 교육 프로그램 개발.</li><li>참여자 접근성 향상을 위한 사용자 친화적 인터페이스 개발.</li><li>블록체인 기반 공론조사의 장기적 비용 효율성 분석 및 최적화.</li></ul></li></ul></li></ol></section>"#.to_string()
    });

    let mut editable = use_signal(|| false);

    rsx! {
        div { class: "flex flex-col gap-4",
            button { onclick: move |_| editable.toggle(), "변경" }
            div { "상태 : {editable}" }
            Typo { variant: Variant::H1, weight: Weight::Extrabold, "TIPTAP EDITOR" }
            TiptapEditor {
                class: "w-full h-fit",
                content: content(),
                editable: editable(),
                placeholder: "Type here...",
                on_content_change: move |html: String| {
                    content.set(html);
                },
            }
        }
    }
}
